import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"在 Windows 上安裝 Java","description":"在 Windows 上安裝 Java 的逐步指南。","frontmatter":{"title":"在 Windows 上安裝 Java","description":"在 Windows 上安裝 Java 的逐步指南。","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"zh_tw/1.21.1/players/installing-java/windows.md","filePath":"versions/1.21.1/translated/zh_tw/players/installing-java/windows.md","lastUpdated":1761424914000}`);var l={name:`zh_tw/1.21.1/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">在 Windows 上安裝 Java <a class="header-anchor" href="#h1" aria-label="Permalink to “在 Windows 上安裝 Java”">​</a></h1><p>這個指南將引導你在 Windows 上安裝 Java 21。</p><p>Minecraft 啟動器附帶了自己的 Java 安裝，因此這部分只在你想使用 Fabric 的 <code>.jar</code> 安裝程式，或者你想使用 Minecraft 伺服器的 <code>.jar</code> 時相關。</p><h2 id="1-check-if-java-is-already-installed" tabindex="-1">1. 檢查 Java 是否已安裝 <a class="header-anchor" href="#1-check-if-java-is-already-installed" aria-label="Permalink to “1. 檢查 Java 是否已安裝”">​</a></h2><p>要檢查 Java 是否已安裝，你首先必須開啟命令提示字元。</p><p>你可以透過按下 <kbd>Win</kbd>+<kbd>R</kbd> 並在出現的對話方塊中輸入 <code>cmd.exe</code> 來執行這項操作。</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Windows執行對話方塊中的「cmd.exe」" loading="lazy"></p><p>開啟命令提示字元後，輸入 <code>java -version</code> 並按下 <kbd>Enter</kbd> 鍵。</p><p>如果命令成功執行，你會看到類似這樣的內容。 如果命令失敗，請繼續進行下一步。</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="命令提示字元中輸入了「java -version」" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>要使用 Minecraft 1.21，你至少需要安裝 Java 21。 如果這個指令顯示任何低於 21 的版本，則需要更新現有的 Java 安裝。</p></div><h2 id="2-download-the-java-installer" tabindex="-1">2. 下載Java 21安裝程式 <a class="header-anchor" href="#2-download-the-java-installer" aria-label="Permalink to “2. 下載Java 21安裝程式”">​</a></h2><p>要安裝Java 21，你需要從 <a href="https://adoptium.net/en-GB/temurin/releases/?os=windows&amp;package=jdk&amp;version=21" target="_blank" rel="noreferrer">Adoptium</a> 下載安裝程式。</p><p>你需要下載 <code>Windows Installer (.msi)</code> 版本：</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Adoptium 下載頁面，突顯了 Windows 安裝程式 (.msi)" loading="lazy"></p><p>如果你有 32 位元作業系統，應該選擇 <code>x86</code>；如果你有 64 位元作業系統，則應該選擇 <code>x64</code>。</p><p>現代大多數電腦都執行 64 位元作業系統。 如果你不確定，請嘗試使用 64 位元的下載。 如果你不確定，請嘗試使用 64 位元的下載。 要檢查 Java 是否已安裝，你首先必須開啟命令提示字元。</p><h2 id="3-run-the-installer" tabindex="-1">3. 執行安裝程式！ <a class="header-anchor" href="#3-run-the-installer" aria-label="Permalink to “3. 執行安裝程式！”">​</a></h2><p>依照安裝程式中的步驟安裝Java 21。 當你到達這個頁面時，你應該將以下功能設為「整個功能將安裝在本機硬碟上」：</p><ul><li><code>設定 JAVA_HOME 變數</code> - 這將加入到你的 PATH 中。</li><li><code>JavaSoft (Oracle) 登錄機碼</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="Java 21 安裝程式，其中「設定 JAVAHOME 變數」和「JavaSoft (Oracle) 登錄機碼」已醒目提示" loading="lazy"></p><p>完成後，你可以按 <code>下一步</code> 繼續安裝。</p><h2 id="4-verify-that-java-is-installed" tabindex="-1">4. 驗證 Java 21 是否已安裝 <a class="header-anchor" href="#4-verify-that-java-is-installed" aria-label="Permalink to “4. 驗證 Java 21 是否已安裝”">​</a></h2><p>安裝完成後，你可以再次開啟命令提示字元，並輸入 <code>java -version</code> 來驗證 Java 21 是否已安裝。</p><p>如果這個命令成功執行，你將看到類似於以前顯示的內容，其中顯示了 Java 版本：</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="命令提示字元中輸入了「java -version」" loading="lazy"></p><p>如果遇到任何問題，你可以在 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> 的 <code>#player-support</code> 頻道中尋求幫助。</p>`,27)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};